180			if !collecting && !strings.HasPrefix(trimmed, "use ") && !strings.HasPrefix(trimmed, "pub use ") && !strings.HasPrefix(trimmed, "pub(crate) use ") && !strings.HasPrefix(trimmed, "pub(super) use ") && !strings.HasPrefix(trimmed, "pub(self) use ") {
181				continue
182			}
183			if stmt.Len() > 0 {
184				stmt.WriteByte(' ')
185			}
186			stmt.WriteString(trimmed)
187			collecting = true
188			if !strings.Contains(trimmed, ";") {
