219	func rustUseImportBindings(expr string) []rustImportBinding {
220		expr = strings.TrimSpace(expr)
221		if expr == "" || strings.Contains(expr, "*") {
222			return nil
223		}
224		if open := rustTopLevelByte(expr, '{'); open >= 0 {
225			close := matchDelimiter([]byte(expr), open)
226			if close < 0 {
227				return nil
228			}
229			prefix := strings.TrimSuffix(strings.TrimSpace(expr[:open]), "::")
230			var out []rustImportBinding
231			for _, item := range splitTopLevelCommas(expr[open+1 : close]) {
232				item = strings.TrimSpace(item)
233				if item == "" {
234					continue
235				}
236				out = append(out, rustUseImportBindings(rustJoinModule(prefix, item))...)
237			}
238			return out
239		}
240		local, module := rustUseTerminalBinding(expr)
241		if local == "" || module == "" {
242			return nil
243		}
244		return []rustImportBinding{{Local: local, Module: module}}
245	}
