247	func rustUseTerminalBinding(expr string) (local, module string) {
248		expr = strings.TrimSpace(expr)
249		if expr == "" {
250			return "", ""
251		}
252		alias := ""
253		if idx := strings.LastIndex(expr, " as "); idx >= 0 {
254			alias = strings.TrimSpace(expr[idx+4:])
255			expr = strings.TrimSpace(expr[:idx])
256		}
257		expr = strings.Trim(expr, ": ")
258		if expr == "" {
259			return "", ""
260		}
261		parts := strings.Split(expr, "::")
262		if len(parts) > 0 && parts[len(parts)-1] == "self" {
263			parts = parts[:len(parts)-1]
264			expr = strings.Join(parts, "::")
265		}
266		if expr == "" {
267			return alias, expr
268		}
269		if alias != "" {
270			return alias, expr
271		}
272		parts = strings.Split(expr, "::")
273		return parts[len(parts)-1], expr
274	}
