276	func rustTopLevelByte(s string, want byte) int {
277		depth := 0
278		for i := 0; i < len(s); i++ {
279			switch s[i] {
280			case '{':
281				if want == '{' && depth == 0 {
282					return i
283				}
284				depth++
285			case '}':
286				if depth > 0 {
287					depth--
288				}
289			}
290		}
291		return -1
292	}
