20		for _, file := range changed {
21			path := file.Path
22			oldPath := file.OldPath
23			if oldPath == "" {
24				oldPath = path
25			}
26			if !Supported(path) && !Supported(oldPath) {
27				continue
28			}
29	
30			var before, after string
31			var beforeOK, afterOK bool
32			if file.Status != "A" {
33				before, beforeOK, err = gitutil.ShowFile(ctx, repo, base, oldPath)
34				if err != nil {
35					return Result{}, err
36				}
37			}
38			if file.Status != "D" {
39				after, afterOK, err = gitutil.ShowFile(ctx, repo, head, path)
40				if err != nil {
41					return Result{}, err
42				}
43			}
44	
45			beforeEntities, language, beforeStatus := parser.ParseWithStatus(oldPath, before)
46			afterEntities, afterLanguage, afterStatus := parser.ParseWithStatus(path, after)
47			if language == "" {
48				language = afterLanguage
49			}
50			// A parse failure on either side degrades the diff. A TOTAL failure
51			// (ParseError with ZERO recovered entities) gives compareEntities no
52			// signal at all and would make it report every entity on that side as
53			// a phantom removed/added, so the delta is skipped and a
54			// machine-readable warning is surfaced instead. A PARTIAL recovery
55			// (ParseError with some entities extracted) keeps the diff — the
56			// recovered changes are real — but is still flagged with a warning,
57			// because symbols missing from the recovered set can surface as
58			// phantom removed/added. A validly-emptied file (ParseError false) is
59			// never suppressed or flagged, so its real removed changes stand.
60			afterParseFailed := afterStatus.ParseError && len(afterEntities) == 0
61			beforeParseFailed := beforeStatus.ParseError && len(beforeEntities) == 0
62			if afterParseFailed || beforeParseFailed {
63				status, warnPath := afterStatus, path
64				if !afterParseFailed {
65					status, warnPath = beforeStatus, oldPath
66				}
67				result.Warnings = append(result.Warnings, parseFailureWarning(warnPath, status, true))
68				continue
69			}
70			if afterStatus.ParseError || beforeStatus.ParseError {
71				status, warnPath := afterStatus, path
72				if !afterStatus.ParseError {
73					status, warnPath = beforeStatus, oldPath
74				}
