128	// parseFailureWarning builds the warning emitted when a changed file fails to
129	// parse on one side of the diff. It reuses the provider path's machine-readable
130	// codes (parseStatus.ParseError → PartialFailure, see provider.go), and both
131	// surfaces warn on any ParseError — but the effect wording is diff-specific:
132	// the provider always emits its (possibly partial) output, while the diff path
133	// suppresses the file's delta entirely on a total failure (suppressed == true)
134	// and keeps a possibly-degraded diff on a partial recovery.
135	func parseFailureWarning(path string, status ParseStatus, suppressed bool) ProviderWarning {
136		code := status.Code
137		if code == "" {
138			code = "E_PARSE_ERROR"
