170	// reconcileMoves matches removed entities in one file against added entities in
171	// another and rewrites unambiguous high-similarity pairs as a single MOVED
172	// change on the destination file. Ambiguous matches are left as remove/add and
173	// reported as warnings. Consumed entities are stripped from the deltas.
174	func reconcileMoves(deltas []*fileDelta) []ProviderWarning {
175		type ref struct {
176			delta  int
177			index  int
178			entity Entity
179			path   string
180		}
181		var removed, added []ref
182		for di, delta := range deltas {
183			for ri, entity := range delta.removed {
184				removed = append(removed, ref{delta: di, index: ri, entity: entity, path: delta.path})
185			}
186			for ai, entity := range delta.added {
187				added = append(added, ref{delta: di, index: ai, entity: entity, path: delta.path})
188			}
189		}
190	
191		usedAdded := make([]bool, len(added))
192		usedRemoved := make(map[[2]int]bool)
193		consumedAdded := make(map[[2]int]bool)
194		var warnings []ProviderWarning
195	
196		for ri := range removed {
197			r := removed[ri]
198			bestAi := -1
199			bestScore := 0.0
200			secondScore := 0.0
201			for ai := range added {
202				if usedAdded[ai] {
203					continue
204				}
205				a := added[ai]
206				if a.path == r.path || a.entity.Kind != r.entity.Kind {
207					continue
208				}
209				score := similarity(r.entity, a.entity)
210				if score > bestScore {
211					secondScore = bestScore
212					bestScore = score
213					bestAi = ai
214				} else if score > secondScore {
215					secondScore = score
216				}
217			}
218			if bestAi < 0 || bestScore < moveThreshold {
219				continue
220			}
221			if secondScore >= moveThreshold && bestScore-secondScore < ambiguityMargin {
222				warnings = append(warnings, ProviderWarning{
223					Code:                 "W_MOVE_AMBIGUOUS",
224					Severity:             "warning",
225					FilePath:             r.path,
226					EffectOnCompleteness: "symbol move could not be reconciled unambiguously; reported as remove/add",
227					Detail:               fmt.Sprintf("%s %s has multiple equally similar destinations", r.entity.Kind, r.entity.Name),
228				})
229				continue
230			}
231	
232			a := added[bestAi]
233			usedAdded[bestAi] = true
234			usedRemoved[[2]int{r.delta, r.index}] = true
235			consumedAdded[[2]int{a.delta, a.index}] = true
236	
237			change := EntityChange{
238				Type:            "moved",
239				Kind:            a.entity.Kind,
240				Name:            a.entity.Name,
241				OldSignature:    r.entity.Signature,
242				NewSignature:    a.entity.Signature,
243				OldPath:         r.path,
244				NewPath:         a.path,
245				BeforeStartLine: r.entity.StartLine,
246				AfterStartLine:  a.entity.StartLine,
247				Similarity:      bestScore,
248				Reconciliation:  "MOVED",
249			}
250			if r.entity.Name != a.entity.Name {
251				change.OldName = r.entity.Name
252				change.NewName = a.entity.Name
253			}
254			deltas[a.delta].changes = append(deltas[a.delta].changes, change)
255		}
256	
257		for di, delta := range deltas {
258			if len(usedRemoved) > 0 {
259				var keep []Entity
260				for ri, entity := range delta.removed {
261					if !usedRemoved[[2]int{di, ri}] {
262						keep = append(keep, entity)
263					}
264				}
265				delta.removed = keep
266			}
267			if len(consumedAdded) > 0 {
268				var keep []Entity
269				for ai, entity := range delta.added {
270					if !consumedAdded[[2]int{di, ai}] {
271						keep = append(keep, entity)
272					}
273				}
274				delta.added = keep
275			}
276		}
277	
278		return warnings
279	}
280	
281	func AnalyzeCheckpoint(ctx context.Context, repo, checkpointID string) (Result, error) {
282		head, err := gitutil.FindCommitWithCheckpoint(ctx, repo, checkpointID)
283		if err != nil {
284			return Result{}, err
285		}
286		base, err := gitutil.FirstParent(ctx, repo, head)
287		if err != nil {
288			return Result{}, err
289		}
290		result, err := AnalyzeGitRange(ctx, repo, base, head, nil)
291		if err != nil {
292			return Result{}, err
293		}
294		result.Checkpoint = checkpointID
295		return result, nil
296	}
297	
298	// Compare reports the entity-level changes between two parses of the same file.
299	// Removed and added entities that are not reconciled within the file (rename)
300	// are emitted as plain removed/added changes.
301	func Compare(before, after []Entity) []EntityChange {
302		changes, removed, added := compareEntities(before, after)
303		for _, oldEntity := range removed {
304			changes = append(changes, removedChange(oldEntity))
305		}
306		for _, newEntity := range added {
307			changes = append(changes, addedChange(newEntity))
308		}
309		sortChanges(changes)
310		return changes
311	}
312	
313	// compareEntities diffs two entity sets from the same file. It returns the
314	// resolved changes (signature/body changes and within-file renames) plus the
315	// removed and added entities that were not reconciled, sorted deterministically
316	// so callers can run a cross-file reconciliation pass over the leftovers.
317	func compareEntities(before, after []Entity) (changes []EntityChange, removed, added []Entity) {
318		beforeByKey, afterByKey := keyedEntityMaps(before, after)
319	
320		deleted := map[string]Entity{}
321		addedByKey := map[string]Entity{}
322	
323		for key, oldEntity := range beforeByKey {
324			newEntity, ok := afterByKey[key]
325			if !ok {
326				deleted[key] = oldEntity
327				continue
328			}
329			switch {
330			case oldEntity.Signature != newEntity.Signature:
331				changes = append(changes, EntityChange{
332					Type:            "signature_changed",
333					Kind:            oldEntity.Kind,
334					Name:            oldEntity.Name,
335					OldSignature:    oldEntity.Signature,
336					NewSignature:    newEntity.Signature,
337					BeforeStartLine: oldEntity.StartLine,
338					AfterStartLine:  newEntity.StartLine,
339				})
340			case oldEntity.BodyHash != newEntity.BodyHash:
341				changes = append(changes, EntityChange{
342					Type:            "body_changed",
343					Kind:            oldEntity.Kind,
344					Name:            oldEntity.Name,
345					BeforeStartLine: oldEntity.StartLine,
346					AfterStartLine:  newEntity.StartLine,
347				})
348			}
349		}
350		for key, newEntity := range afterByKey {
351			if _, ok := beforeByKey[key]; !ok {
352				addedByKey[key] = newEntity
353			}
354		}
355	
356		for oldKey, oldEntity := range deleted {
357			bestKey, bestEntity, score := bestRename(oldEntity, addedByKey)
358			if score >= renameThreshold {
359				delete(deleted, oldKey)
360				delete(addedByKey, bestKey)
361				changes = append(changes, EntityChange{
362					Type:            "renamed",
363					Kind:            oldEntity.Kind,
364					Name:            bestEntity.Name,
365					OldName:         oldEntity.Name,
366					NewName:         bestEntity.Name,
367					OldSignature:    oldEntity.Signature,
368					NewSignature:    bestEntity.Signature,
369					BeforeStartLine: oldEntity.StartLine,
370					AfterStartLine:  bestEntity.StartLine,
371					Similarity:      score,
372					Reconciliation:  "RENAMED",
373				})
374			}
375		}
376	
377		removed = sortedEntities(deleted)
378		added = sortedEntities(addedByKey)
379		return changes, removed, added
380	}
381	
382	const (
383		renameThreshold = 0.92
384		moveThreshold   = 0.92
385		// ambiguityMargin marks a move as ambiguous when a second candidate scores
386		// within this distance of the best one, so we report remove/add and warn
387		// rather than guessing.
388		ambiguityMargin = 0.05
389	)
390	
391	func removedChange(oldEntity Entity) EntityChange {
392		return EntityChange{
393			Type:            "removed",
394			Kind:            oldEntity.Kind,
395			Name:            oldEntity.Name,
396			OldSignature:    oldEntity.Signature,
397			BeforeStartLine: oldEntity.StartLine,
398		}
399	}
400	
401	func addedChange(newEntity Entity) EntityChange {
402		return EntityChange{
403			Type:           "added",
404			Kind:           newEntity.Kind,
405			Name:           newEntity.Name,
406			NewSignature:   newEntity.Signature,
407			AfterStartLine: newEntity.StartLine,
408		}
409	}
410	
411	func sortedEntities(byKey map[string]Entity) []Entity {
412		keys := make([]string, 0, len(byKey))
413		for k := range byKey {
414			keys = append(keys, k)
415		}
416		sort.Strings(keys)
417		out := make([]Entity, 0, len(byKey))
418		for _, k := range keys {
419			out = append(out, byKey[k])
420		}
421		return out
422	}
423	
424	func sortChanges(changes []EntityChange) {
425		sort.Slice(changes, func(i, j int) bool {
426			left, right := changes[i], changes[j]
427			if leftLine, rightLine := lineForSort(left), lineForSort(right); leftLine != rightLine {
428				return leftLine < rightLine
429			}
430			if left.Kind != right.Kind {
431				return left.Kind < right.Kind
432			}
433			if left.Name != right.Name {
434				return left.Name < right.Name
435			}
436			if left.Type != right.Type {
437				return left.Type < right.Type
438			}
439			if left.OldSignature != right.OldSignature {
440				return left.OldSignature < right.OldSignature
441			}
442			if left.NewSignature != right.NewSignature {
443				return left.NewSignature < right.NewSignature
444			}
445			if left.BeforeStartLine != right.BeforeStartLine {
446				return left.BeforeStartLine < right.BeforeStartLine
447			}
448			if left.AfterStartLine != right.AfterStartLine {
449				return left.AfterStartLine < right.AfterStartLine
450			}
451			if left.OldName != right.OldName {
452				return left.OldName < right.OldName
453			}
454			if left.NewName != right.NewName {
455				return left.NewName < right.NewName
456			}
457			if left.OldPath != right.OldPath {
458				return left.OldPath < right.OldPath
459			}
460			if left.NewPath != right.NewPath {
461				return left.NewPath < right.NewPath
462			}
463			if left.Reconciliation != right.Reconciliation {
464				return left.Reconciliation < right.Reconciliation
465			}
466			if left.Similarity != right.Similarity {
467				return left.Similarity < right.Similarity
468			}
469			return left.DependentsCount < right.DependentsCount
470		})
471	}
472	
473	// keyedEntityMaps assigns each entity an ephemeral key such that entities that
474	// should be diffed against each other receive the same key on both sides. The
475	// keys are opaque: they are used only inside compareEntities/bestRename and are
476	// never persisted or emitted.
477	//
478	// Matching is evidence-first within each Kind:Name group:
479	//
480	//  1. Exact-signature entities pair as content multisets: combined body and
481	//     fingerprint evidence first, then body hash, then fingerprint. Members
482	//     of an equal-content class are interchangeable, so repeated hashes pair
483	//     safely up to the count present on both sides. This keeps an inserted
484	//     exact-signature duplicate from shifting every surviving duplicate.
485	//
486	//  2. Remaining exact signatures pair by occurrence before leftovers take
487	//     unambiguous fingerprint/body anchors across signatures. This prevents
488	//     copied or swapped bodies from stealing an unchanged signature, while the
489	//     identity anchors preserve the right survivor when one overload is removed
490	//     as another changes signature. A final positional fallback still reports
491	//     an otherwise-unanchored in-place signature edit as signature_changed
492	//     rather than remove+add (issue #35). Multiple residuals without identity
493	//     evidence remain inherently ambiguous; their positional pairing is
494	//     retained as a compatibility heuristic.
495	//
496	// Numeric pair keys and side-specific unmatched keys avoid delimiter aliasing
497	// with source-language names and signatures.
498	func keyedEntityMaps(before, after []Entity) (map[string]Entity, map[string]Entity) {
499		type groupKey struct {
500			kind string
501			name string
502		}
503		type entityGroup struct {
504			before []int
505			after  []int
506		}
507	
508		groups := map[groupKey]*entityGroup{}
509		groupFor := func(entity Entity) *entityGroup {
510			key := groupKey{kind: entity.Kind, name: entity.Name}
511			group := groups[key]
512			if group == nil {
513				group = &entityGroup{}
514				groups[key] = group
515			}
516			return group
517		}
518		for i, entity := range before {
519			group := groupFor(entity)
520			group.before = append(group.before, i)
521		}
522		for i, entity := range after {
523			group := groupFor(entity)
524			group.after = append(group.after, i)
525		}
526	
527		groupKeys := make([]groupKey, 0, len(groups))
528		for key := range groups {
529			groupKeys = append(groupKeys, key)
530		}
531		sort.Slice(groupKeys, func(i, j int) bool {
532			if groupKeys[i].kind != groupKeys[j].kind {
533				return groupKeys[i].kind < groupKeys[j].kind
534			}
535			return groupKeys[i].name < groupKeys[j].name
536		})
537	
538		beforeByKey := make(map[string]Entity, len(before))
539		afterByKey := make(map[string]Entity, len(after))
540		beforeMatched := make([]bool, len(before))
541		afterMatched := make([]bool, len(after))
542		pairCount := 0
543	
544		pair := func(beforeIndex, afterIndex int) {
545			key := fmt.Sprintf("=%09d", pairCount)
546			pairCount++
547			beforeMatched[beforeIndex] = true
548			afterMatched[afterIndex] = true
549			beforeByKey[key] = before[beforeIndex]
550			afterByKey[key] = after[afterIndex]
551		}
552		type evidenceKey struct {
553			signature   string
554			bodyHash    string
555			fingerprint string
556		}
557		matchClass := func(group *entityGroup, keyFor func(Entity) (evidenceKey, bool)) {
558			afterBuckets := map[evidenceKey][]int{}
559			for _, afterIndex := range group.after {
560				if afterMatched[afterIndex] {
561					continue
562				}
563				key, ok := keyFor(after[afterIndex])
564				if ok {
565					afterBuckets[key] = append(afterBuckets[key], afterIndex)
566				}
567			}
568			afterOffsets := map[evidenceKey]int{}
569			for _, beforeIndex := range group.before {
570				if beforeMatched[beforeIndex] {
571					continue
572				}
573				key, ok := keyFor(before[beforeIndex])
574				if !ok {
575					continue
576				}
577				offset := afterOffsets[key]
578				if offset >= len(afterBuckets[key]) {
579					continue
580				}
581				pair(beforeIndex, afterBuckets[key][offset])
582				afterOffsets[key]++
583			}
584		}
585		matchUnique := func(group *entityGroup, keyFor func(Entity) (evidenceKey, bool)) {
586			beforeCounts := map[evidenceKey]int{}
587			afterCounts := map[evidenceKey]int{}
588			afterIndexByKey := map[evidenceKey]int{}
589			for _, beforeIndex := range group.before {
590				if beforeMatched[beforeIndex] {
591					continue
592				}
593				if key, ok := keyFor(before[beforeIndex]); ok {
594					beforeCounts[key]++
595				}
596			}
597			for _, afterIndex := range group.after {
598				if afterMatched[afterIndex] {
599					continue
600				}
601				if key, ok := keyFor(after[afterIndex]); ok {
602					afterCounts[key]++
603					afterIndexByKey[key] = afterIndex
604				}
605			}
606			for _, beforeIndex := range group.before {
607				if beforeMatched[beforeIndex] {
608					continue
609				}
610				key, ok := keyFor(before[beforeIndex])
611				if ok && beforeCounts[key] == 1 && afterCounts[key] == 1 {
612					pair(beforeIndex, afterIndexByKey[key])
613				}
614			}
615		}
616		matchRemaining := func(group *entityGroup) {
617			afterRemaining := make([]int, 0, len(group.after))
618			for _, afterIndex := range group.after {
619				if !afterMatched[afterIndex] {
620					afterRemaining = append(afterRemaining, afterIndex)
621				}
622			}
623			afterOffset := 0
624			for _, beforeIndex := range group.before {
625				if beforeMatched[beforeIndex] || afterOffset >= len(afterRemaining) {
626					continue
627				}
628				pair(beforeIndex, afterRemaining[afterOffset])
629				afterOffset++
630			}
631		}
632	
633		for _, key := range groupKeys {
634			group := groups[key]
635			matchClass(group, func(entity Entity) (evidenceKey, bool) {
636				ok := entity.BodyHash != "" && entity.Fingerprint != ""
637				return evidenceKey{signature: entity.Signature, bodyHash: entity.BodyHash, fingerprint: entity.Fingerprint}, ok
638			})
639			matchClass(group, func(entity Entity) (evidenceKey, bool) {
640				return evidenceKey{signature: entity.Signature, bodyHash: entity.BodyHash}, entity.BodyHash != ""
641			})
642			matchClass(group, func(entity Entity) (evidenceKey, bool) {
643				return evidenceKey{signature: entity.Signature, fingerprint: entity.Fingerprint}, entity.Fingerprint != ""
644			})
645			matchClass(group, func(entity Entity) (evidenceKey, bool) {
646				return evidenceKey{signature: entity.Signature}, true
647			})
648			matchUnique(group, func(entity Entity) (evidenceKey, bool) {
649				ok := entity.BodyHash != "" && entity.Fingerprint != ""
650				return evidenceKey{bodyHash: entity.BodyHash, fingerprint: entity.Fingerprint}, ok
651			})
652			matchUnique(group, func(entity Entity) (evidenceKey, bool) {
653				return evidenceKey{fingerprint: entity.Fingerprint}, entity.Fingerprint != ""
654			})
655			matchUnique(group, func(entity Entity) (evidenceKey, bool) {
656				return evidenceKey{bodyHash: entity.BodyHash}, entity.BodyHash != ""
657			})
658			matchRemaining(group)
659		}
660	
661		for i, entity := range before {
662			if !beforeMatched[i] {
663				beforeByKey[fmt.Sprintf("-before:%09d", i)] = entity
664			}
665		}
666		for i, entity := range after {
667			if !afterMatched[i] {
668				afterByKey[fmt.Sprintf("+after:%09d", i)] = entity
669			}
670		}
671		return beforeByKey, afterByKey
672	}
673	
674	func lineForSort(change EntityChange) int {
675		if change.AfterStartLine > 0 {
676			return change.AfterStartLine
677		}
678		return change.BeforeStartLine
679	}
680	
681	func bestRename(old Entity, added map[string]Entity) (string, Entity, float64) {
682		var bestKey string
683		var best Entity
684		var bestScore float64
685		for key, candidate := range added {
686			if candidate.Kind != old.Kind {
687				continue
688			}
689			score := similarity(old, candidate)
690			if score > bestScore {
691				bestKey = key
692				best = candidate
693				bestScore = score
694			}
695		}
696		return bestKey, best, bestScore
697	}
698	
699	func similarity(a, b Entity) float64 {
700		if a.Fingerprint != "" && a.Fingerprint == b.Fingerprint {
701			return 1
702		}
703		if a.BodyHash != "" && a.BodyHash == b.BodyHash {
704			return 0.97
705		}
706		return jaccard(a.Signature, b.Signature)
707	}
708	
709	func jaccard(a, b string) float64 {
710		left := tokenSet(a)
711		right := tokenSet(b)
712		if len(left) == 0 && len(right) == 0 {
713			return 1
714		}
715		var intersection int
716		for token := range left {
717			if right[token] {
718				intersection++
719			}
720		}
721		union := len(left) + len(right) - intersection
722		if union == 0 {
723			return 0
724		}
725		return math.Round((float64(intersection)/float64(union))*100) / 100
726	}
727	
728	func tokenSet(value string) map[string]bool {
729		out := map[string]bool{}
730		token := ""
731		for _, r := range value {
732			if (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_' {
733				token += string(r)
734				continue
735			}
736			if token != "" {
737				out[token] = true
738				token = ""
739			}
740		}
741		if token != "" {
742			out[token] = true
743		}
744		return out
745	}
