}
`)
	writeFile(t, repo, "beta/parser.go", `package beta

func ParseArray() int { return 2 }
`)
	writeFile(t, repo, "gamma/doc_test.go", `package gamma

import "testing"

func TestParseArray(t *testing.T) {}
`)

